1	package fan.summer;
2	
3	/**
4	 * Fat JAR / classpath launch entry point.
5	 *
6	 * Must be separate from ToolboxApp (extends Application).
7	 * JavaFX module system requires: when using a class that extends Application
8	 * as the main class, javafx.graphics needs to be on the module-path,
9	 * not classpath. Using this non-Application intermediate class for launch
10	 * allows compatibility with classpath mode (lib/ directory).
11	 */
12	public class Launcher {
13	    public static void main(String[] args) {
14	        fan.summer.app.SwissKitJApp.main(args);
15	    }
16	}
